export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "12:28。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "裝卸區。顧言站在鋼棚的最外側，背靠一根鏽蝕的鐵柱。雨打在鐵皮頂上，發出很均勻的、像在數拍子的聲響。裝卸平台上堆著捲起來的延長線、備用燈架、幾個沒有貼標籤的木箱。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠在他左前方兩步遠，相機掛在脖子上，手指搭在鏡頭蓋邊緣。她從剛才到現在沒有看他，也沒有說話。她在等。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第三件。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）09:30，林主任封照片區。中了。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）10:15，南翼備用門禁卡。中了。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）12:30——", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "腳步聲從裝卸區側門傳過來。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是工作人員那種帶著鑰匙碰撞聲的步伐。是一種很快、壓抑著力道、像在走其實已在跑的步伐。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越從側門拐進來。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校服外面罩著那件沾灰塵的深色外套，脖子上的「舞台組」臨時通行證被雨打濕了一角。他單手提著一個黑色硬殼相機包——包側面貼著一條手寫的膠帶，上面用奇異筆寫著：直播備份線材。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的視線第一個落在顧言身上。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "他怎麼在這。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是問句。是控訴。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "他說中了兩件。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "說中了不代表不是他們的人。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有把包放下。包被提在手裡，像隨時可以轉身帶走。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他在保護她。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他怕我。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯和他怕的是同一件事。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "許星棠，妳——", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "放著。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的聲音很低，沒有回頭。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "包放著。我看看。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越盯了她兩秒。然後他把黑色硬殼包放到裝卸平台邊緣，手沒有立刻離開包柄。最後他鬆手，退後半步，站到一個可以同時看到包和側門的位置。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他不再看許星棠。他的視線釘在顧言身上。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他怕我碰這個包。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這個包對他來說不是器材。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯是釣餌。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他在等我靠近它。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠沒有去開包。她只是站在那裡，像在等什麼。她按在快門側面的手指沒有按下。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "12:30。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "遠處廣播響了——校慶導覽組的午間提醒，內容是什麼顧言沒有聽進去。他在等的不是這個。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "第三件成立。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "包在這。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你要不要打開看看。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她給我開包的機會。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯她在測我會不會去搶。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她還沒有完全相信我。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "不用。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）如果我打開它，她會知道我有多想要裡面的東西。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我偏不碰。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有走近那個包。他連視線都沒有落在上面。他看著韓越。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）打開它的人，第二輪見過。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不是他們三個裡的任何一個。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）是那個穿黑雨衣的。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的喉嚨動了一下。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "不是這個。東西沒出來。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "裝卸區的雨聲在這一秒變得很大。或者只是耳朵裡血往上衝的聲音變得很大。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越的臉色變了。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是驚訝。不是憤怒。是一種更深的東西——像有人把他一直以為只有自己知道的秘密，突然當眾念出來。他的下頷收緊，右手無意識地握成拳頭。手背上那幾道平行的暗紅薄痂在灰光下看得見。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "⋯⋯你聽到的是原話？", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "一字不差。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "那個人長什麼樣。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他知道。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他在問細節，是為了確認我沒有在騙他。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "黑雨衣。帽沿壓低。皮鞋。動作不急。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "⋯⋯", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "夠了。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的聲音把兩個人都壓住。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "包是空的。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "標籤是我們貼的。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "我們要看——誰會來攔。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她承認了。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）誘餌。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第二輪——", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）那輛車。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我躲進那輛校務車的器材廂，因為我在逃命。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）車上有一個黑色的硬殼包。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯就是這一個。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）就是他們放出去測攔截線的這一個。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）黑雨衣上車，翻開包，說——「不是這個。東西沒出來。」", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他不是來找我的。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他甚至不知道我在車廂裡。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他在找相機。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的呼吸慢了下來。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第二輪那場車禍。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我以為是被精準追殺。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯不是。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我闖進了一條已經有人盯著的線。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他們攔的不是我。是那個包。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）車失控——是攔截的動作疊上颱風、疊上路況、疊上一個不該在那裡的我。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯不是命運。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）是混亂。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越一直盯著他。他看出顧言的臉色變了。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "你想到什麼。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯那輛車。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "⋯⋯", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.HanYue_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "你們把空包送上車。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "我躲上去。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "黑雨衣上來攔。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯車翻了。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越的下頷動了一下。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "那個包是用來釣人的，不是用來救你的。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "我知道。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "所以車翻的時候——", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "你們想到的是包，不是我。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "⋯⋯", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越沒有立刻接話。他張了一下嘴，又合上。喉結上下滾了一下。然後他別開臉，看著裝卸區外那片被雨打得發白的水泥地。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "我不知道你會上去。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是道歉。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但也不是否認。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠轉過頭看了韓越一眼。她什麼都沒說。但她按在快門上的手指鬆開了。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他不是冷血。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他只是不知道。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他設了一個局，局裡本來不應該有我。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯結果我闖進去，死了。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他活下來，帶著這件事。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "12:34。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "裝卸區後方的鐵捲門被風吹得發出一聲低嘯。韓越把空包重新拎起來，動作很輕——和剛才提著它進來時的力道完全不一樣。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "包我先帶回去。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "嗯。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "下午再說。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.HanYue_Angry },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他轉身走進側門。腳步聲很快，比進來時更快。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "裝卸區只剩下顧言和許星棠。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "第三件成立。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "今晚之前，不插手。這是規矩。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯嗯。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "下午一點二十。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "舊圖書室後方的暗房。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你來。把話說完。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有等他回答。她把相機往胸前撥了一下，轉身從另一個出口走出去。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "裝卸區的雨還在下。鐵皮頂上那個均勻的拍子還在繼續。", background: Background.Chapter_6_Ch6_Act5_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯她讓我去。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）三件都中了。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她終於願意聽。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）下午一點二十。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）暗房。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯把話說完。", background: Background.Chapter_6_Ch6_Act5_S0, portrait: Portrait.GuYan_Determined },
];
